func BuiltinVectorIntReadJSONGeneral(jctx *basictl.JSONReadContext, in *basictl.JsonLexer, vec *[]int32) error {
	*vec = (*vec)[:cap(*vec)]
	index := 0
	if in != nil {
		in.Delim('[')
		if !in.Ok() {
			return ErrorInvalidJSON("[]int32", "expected json array")
		}
		for ; !in.IsDelim(']'); index++ {
			if len(*vec) <= index {
				var newValue int32
				*vec = append(*vec, newValue)
				*vec = (*vec)[:cap(*vec)]
			}
			if err := Json2ReadInt32(in, &(*vec)[index]); err != nil {
				return err
			}
			in.WantComma()
		}
		in.Delim(']')
		if !in.Ok() {
			return ErrorInvalidJSON("[]int32", "expected json array's end")
		}
	}
	*vec = (*vec)[:index]
	return nil
}

func BuiltinVectorIntWriteJSON(w []byte, vec []int32) []byte {
	return BuiltinVectorIntWriteJSONOpt(nil, w, vec)
}
func BuiltinVectorIntWriteJSONOpt(jctx *basictl.JSONWriteContext, w []byte, vec []int32) []byte {
	w = append(w, '[')
	for _, elem := range vec {
		w = basictl.JSONAddCommaIfNeeded(w)
		w = basictl.JSONWriteInt32(w, elem)
	}
	return append(w, ']')
}

// BASE TYPES
type Int int32

func (item *Int) ptr() *int32 { return (*int32)(item) }

func (Int) TLName() string { return "int" }
func (Int) TLTag() uint32  { return 0xa8509bda }

func (item *Int) Reset() {
	*item.ptr() = 0
}

func (item *Int) FillRandom(rg *basictl.RandGenerator) {
	*item.ptr() = basictl.RandomInt(rg)
}

func (item *Int) ReadTL1(w []byte) (_ []byte, err error) {
	return basictl.IntRead(w, item.ptr())
}

func (item *Int) WriteTL1General(w []byte) (_ []byte, err error) {
	return item.WriteTL1(w), nil
}

func (item *Int) WriteTL1(w []byte) []byte {
	w = basictl.IntWrite(w, *item.ptr())
	return w
}

func (item *Int) ReadTL1Boxed(w []byte) (_ []byte, err error) {
	if w, err = basictl.NatReadExactTag(w, 0xa8509bda); err != nil {
		return w, err
	}
	return item.ReadTL1(w)
}

func (item *Int) WriteTL1BoxedGeneral(w []byte) (_ []byte, err error) {
	return item.WriteTL1Boxed(w), nil
}

func (item *Int) WriteTL1Boxed(w []byte) []byte {
	w = basictl.NatWrite(w, 0xa8509bda)
	return item.WriteTL1(w)
}

func (item Int) String() string {
	return string(item.WriteJSON(nil))
}
func (item *Int) ReadJSON(legacyTypeNames bool, in *basictl.JsonLexer) error {
	jctx := basictl.JSONReadContext{LegacyTypeNames: legacyTypeNames}
	return item.ReadJSONGeneral(&jctx, in)
}

func (item *Int) ReadJSONGeneral(jctx *basictl.JSONReadContext, in *basictl.JsonLexer) error {
	if err := Json2ReadInt32(in, item.ptr()); err != nil {
		return err
	}
	return nil
}

// This method is general version of WriteJSON, use it instead!
func (item *Int) WriteJSONGeneral(jctx *basictl.JSONWriteContext, w []byte) (_ []byte, err error) {
	return item.WriteJSONOpt(jctx, w), nil
}

func (item *Int) WriteJSON(w []byte) []byte {
	return item.WriteJSONOpt(nil, w)
}

func (item *Int) WriteJSONOpt(jctx *basictl.JSONWriteContext, w []byte) []byte {
	w = basictl.JSONWriteInt32(w, *item.ptr())
	return w
}
func (item *Int) MarshalJSON() ([]byte, error) {
	return item.WriteJSON(nil), nil
}

func (item *Int) UnmarshalJSON(b []byte) error {
	if err := item.ReadJSON(true, &basictl.JsonLexer{Data: b}); err != nil {
		return ErrorInvalidJSON("int", err.Error())
	}
	return nil
}

func (item *Int) WriteTL2(w []byte, ctx *basictl.TL2WriteContext) []byte {
	var sizes []int
	if ctx != nil {
		sizes = ctx.SizeBuffer[:0]
	}
	var sz int
	var currentSize int
	currentSize += 4
	w = basictl.IntWrite(w, *item.ptr())

	Unused(currentSize)
	Unused(sz)
	if ctx != nil {
		ctx.SizeBuffer = sizes
	}
	return w
}

func (item *Int) InternalReadTL2(r []byte) (_ []byte, err error) {
	if r, err = basictl.IntRead(r, item.ptr()); err != nil {
		return r, err
	}
	return r, nil
}

func (item *Int) ReadTL2(r []byte, ctx *basictl.TL2ReadContext) (_ []byte, err error) {
	return item.InternalReadTL2(r)
}

type IntMaybe struct {
	Value int32 // not deterministic if !Ok
	Ok    bool
}

func (item *IntMaybe) Reset() {
	item.Ok = false
}
func (item *IntMaybe) FillRandom(rg *basictl.RandGenerator) {
	if basictl.RandomUint(rg)&1 == 1 {
		item.Ok = true
		item.Value = basictl.RandomInt(rg)
	} else {
		item.Ok = false
	}
}

func (item *IntMaybe) ReadTL1Boxed(w []byte) (_ []byte, err error) {
	if w, err = basictl.ReadBool(w, &item.Ok, 0x27930a7b, 0x3f9c8ef8); err != nil {
		return w, err
	}
	if item.Ok {
		return basictl.IntRead(w, &item.Value)
	}
	return w, nil
}

func (item *IntMaybe) WriteTL1Boxed(w []byte) []byte {
	if item.Ok {
		w = basictl.NatWrite(w, 0x3f9c8ef8)
		return basictl.IntWrite(w, item.Value)
	}
	return basictl.NatWrite(w, 0x27930a7b)
}

func (item *IntMaybe) CalculateLayout(sizes []int, optimizeEmpty bool) ([]int, int) {
	if !item.Ok {
		if optimizeEmpty {
			return sizes, 0
		}
		return sizes, 1
	}
	sizePosition := len(sizes)
	sizes = append(sizes, 0)

	currentSize := 1
	lastUsedByte := 0
	var sz int

	currentSize += basictl.TL2CalculateSize(1)
	lastUsedByte = currentSize

	if item.Value != 0 {
		currentSize += 4
		lastUsedByte = currentSize
	}

	if lastUsedByte < currentSize {
		currentSize = lastUsedByte
	}
	sizes[sizePosition] = currentSize
	currentSize += basictl.TL2CalculateSize(currentSize)
	Unused(sz)
	return sizes, currentSize
}

func (item *IntMaybe) InternalWriteTL2(w []byte, sizes []int, optimizeEmpty bool) ([]byte, []int, int) {
	if !item.Ok {
		if optimizeEmpty {
			return w, sizes, 0
		}
		w = append(w, 0)
		return w, sizes, 1
	}
	currentSize := sizes[0]
	sizes = sizes[1:]
	w = basictl.TL2WriteSize(w, currentSize)
	oldLen := len(w)
	var sz int
	var currentBlock byte
	currentBlockPosition := len(w)
	w = append(w, 0)

	w = basictl.TL2WriteSize(w, 1)
	currentBlock |= 1
	if item.Value != 0 {
		w = basictl.IntWrite(w, item.Value)
		currentBlock |= 2
	}
	w[currentBlockPosition] = currentBlock
	if len(w)-oldLen != currentSize {
		panic("tl2: mismatch between calculate and write")
	}
	Unused(sz)
	return w, sizes, currentSize
}

func (item *IntMaybe) InternalReadTL2(r []byte) (_ []byte, err error) {
	currentSize := 0
	if r, currentSize, err = basictl.TL2ParseSize(r); err != nil {
		return r, err
	}
	if currentSize == 0 {
		item.Reset()
		return r, nil
	}
	if len(r) < currentSize {
		return r, basictl.TL2Error("not enough data: expected %d, got %d", currentSize, len(r))
	}
	currentR := r[:currentSize]
	r = r[currentSize:]

	var block byte
	if currentR, err = basictl.ByteRead(currentR, &block); err != nil {
		return r, err
	}
	var index int
	if (block & 1) != 0 {
		if currentR, index, err = basictl.TL2ParseSize(currentR); err != nil {
			return r, err
		}
	}
	switch index {
	case 0:
		item.Ok = false
		return r, nil
	case 1:
		item.Ok = true
	default:
		return r, ErrorInvalidUnionIndex("Maybe", index)
	}

	if block&2 != 0 {
		if currentR, err = basictl.IntRead(currentR, &item.Value); err != nil {
			return currentR, err
		}
	} else {
		item.Value = 0
	}
	return r, nil
}

func (item *IntMaybe) ReadJSONGeneral(jctx *basictl.JSONReadContext, in *basictl.JsonLexer) error {
	_ok, _jvalue, err := Json2ReadMaybe("Maybe", in)
	if err != nil {
		return err
	}
	item.Ok = _ok
	if _ok {
		var in2Pointer *basictl.JsonLexer
		if _jvalue != nil {
			in2 := basictl.JsonLexer{Data: _jvalue}
			in2Pointer = &in2
		}
		if err := Json2ReadInt32(in2Pointer, &item.Value); err != nil {
			return err
		}
	}
	return nil
}

// This method is general version of WriteJSON, use it instead!
func (item *IntMaybe) WriteJSONGeneral(jctx *basictl.JSONWriteContext, w []byte) (_ []byte, err error) {
	return item.WriteJSONOpt(jctx, w), nil
}

func (item *IntMaybe) WriteJSON(w []byte) []byte {
	return item.WriteJSONOpt(nil, w)
}
func (item *IntMaybe) WriteJSONOpt(jctx *basictl.JSONWriteContext, w []byte) []byte {
	if !item.Ok {
		return append(w, "{}"...)
	}
	w = append(w, `{"ok":true`...)
	if item.Value != 0 {
		w = append(w, `,"value":`...)
		w = basictl.JSONWriteInt32(w, item.Value)
	}
	return append(w, '}')
}

func (item IntMaybe) String() string {
	return string(item.WriteJSON(nil))
}
